/**
 * SecureKeyManager handles private key storage and retrieval
 * using encrypted keystore files. Private keys are NEVER stored
 * in plaintext, logged, or exposed in error messages.
 */
class SecureKeyManager {
  constructor(keystorePath, encryptionKey) {
    if (!keystorePath || !encryptionKey) {
      throw new Error("Keystore path and encryption key are required");
    }
    this.keystorePath = path.resolve(keystorePath);
    // Derive a 256-bit key from the provided encryption key
    this.encryptionKey = crypto.scryptSync(encryptionKey, "dapp-salt-v1", 32);

    // Ensure keystore directory exists with restricted permissions
    if (!fs.existsSync(this.keystorePath)) {
      fs.mkdirSync(this.keystorePath, { recursive: true, mode: 0o700 });
    }
  }

  /**
   * Encrypt and store a private key associated with an alias.
   * The private key is encrypted at rest using AES-256-GCM.
   */
  storeKey(alias, privateKey) {
    this._validateAlias(alias);
    this._validatePrivateKey(privateKey);

    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv("aes-256-gcm", this.encryptionKey, iv);

    let encrypted = cipher.update(privateKey, "utf8", "hex");
    encrypted += cipher.final("hex");
    const authTag = cipher.getAuthTag();

    const keyData = {
      iv: iv.toString("hex"),
      authTag: authTag.toString("hex"),
      encryptedKey: encrypted,
      createdAt: new Date().toISOString(),
    };

    const filePath = path.join(this.keystorePath, `${alias}.enc`);
    fs.writeFileSync(filePath, JSON.stringify(keyData), {
      encoding: "utf8",
      mode: 0o600,
    });

    // Clear sensitive data from memory
    privateKey = null;

    console.log(`[KeyManager] Key stored securely for alias: ${alias}`);
  }

  /**
   * Retrieve and decrypt a private key by alias.
   * Returns an ethers.js Wallet instance (key is never returned as string).
   */
  getWallet(alias, provider) {
    this._validateAlias(alias);

    const filePath = path.join(this.keystorePath, `${alias}.enc`);
    if (!fs.existsSync(filePath)) {
      throw new Error(`No key found for alias: ${alias}`);
    }

    const keyData = JSON.parse(fs.readFileSync(filePath, "utf8"));
    const iv = Buffer.from(keyData.iv, "hex");
    const authTag = Buffer.from(keyData.authTag, "hex");

    const decipher = crypto.createDecipheriv(
      "aes-256-gcm",
      this.encryptionKey,
      iv
    );
    decipher.setAuthTag(authTag);

    let decrypted = decipher.update(keyData.encryptedKey, "hex", "utf8");
    decrypted += decipher.final("utf8");

    const wallet = new ethers.Wallet(decrypted, provider);

    // Clear decrypted key from memory
    decrypted = null;

    return wallet;
  }

  /**
   * List available key aliases (never exposes actual keys).
   */
  listAliases() {
    const files = fs.readdirSync(this.keystorePath);
    return files
      .filter((f) => f.endsWith(".enc"))
      .map((f) => f.replace(".enc", ""));
  }

  /**
   * Delete a stored key by alias.
   */
  deleteKey(alias) {
    this._validateAlias(alias);
    const filePath = path.join(this.keystorePath, `${alias}.enc`);
    if (fs.existsSync(filePath)) {
      // Overwrite file content before deletion
      const size = fs.statSync(filePath).size;
      fs.writeFileSync(filePath, crypto.randomBytes(size));
      fs.unlinkSync(filePath);
      console.log(`[KeyManager] Key deleted for alias: ${alias}`);
    }
  }

  _validateAlias(alias) {
    if (!alias || typeof alias !== "string") {
      throw new Error("Alias must be a non-empty string");
    }
    // Prevent path traversal attacks
    if (!/^[a-zA-Z0-9_-]+$/.test(alias)) {
      throw new Error(
        "Alias must contain only alphanumeric characters, hyphens, and underscores"
      );
    }
    if (alias.length > 64) {
      throw new Error("Alias must be 64 characters or fewer");
    }
  }

  _validatePrivateKey(privateKey) {
    if (!privateKey || typeof privateKey !== "string") {
      throw new Error("Private key must be a non-empty string");
    }
    // Validate it's a valid hex private key
    const cleanKey = privateKey.startsWith("0x")
      ? privateKey.slice(2)
      : privateKey;
    if (!/^[a-fA-F0-9]{64}$/.test(cleanKey)) {
      throw new Error("Invalid private key format");
    }
  }
}

