class InputValidator {
  static validateAddress(address) {
    if (!address || typeof address !== "string") {
      throw new Error("Address must be a non-empty string");
    }
    if (!ethers.isAddress(address)) {
      throw new Error(`Invalid Ethereum address: ${address.substring(0, 10)}...`);
    }
    return ethers.getAddress(address); // Returns checksummed address
  }

  static validateAmount(amount) {
    if (amount === undefined || amount === null) {
      throw new Error("Amount is required");
    }
    const amountStr = String(amount);
    // Validate it's a valid decimal number
    if (!/^\d+(\.\d+)?$/.test(amountStr)) {
      throw new Error("Amount must be a positive decimal number");
    }
    const parsed = parseFloat(amountStr);
    if (parsed <= 0) {
      throw new Error("Amount must be greater than zero");
    }
    if (parsed > 1000000) {
      throw new Error("Amount exceeds maximum allowed value");
    }
    return amountStr;
  }

  static validateUint256(value) {
    if (value === undefined || value === null) {
      throw new Error("Value is required");
    }
    try {
      const bn = BigInt(value);
      if (bn < 0n) {
        throw new Error("Value must be non-negative");
      }
      if (bn > 2n ** 256n - 1n) {
        throw new Error("Value exceeds uint256 maximum");
      }
      return bn;
    } catch (e) {
      if (e.message.includes("Value")) throw e;
      throw new Error("Invalid uint256 value");
    }
  }

  static validateContractABI(abi) {
    if (!Array.isArray(abi)) {
      throw new Error("ABI must be an array");
    }
    if (abi.length === 0) {
      throw new Error("ABI must not be empty");
    }
    // Basic structural validation
    for (const item of abi) {
      if (typeof item !== "object" || item === null) {
        throw new Error("Each ABI entry must be an object");
      }
    }
    return abi;
  }

  static validateFunctionName(name) {
    if (!name || typeof name !== "string") {
      throw new Error("Function name must be a non-empty string");
    }
    if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(name)) {
      throw new Error("Invalid function name format");
    }
    if (name.length > 256) {
      throw new Error("Function name too long");
    }
    return name;
  }

  static validateChainId(chainId) {
    const id = Number(chainId);
    const allowedChains = [1, 5, 11155111, 137, 80001, 42161, 421613];
    if (!allowedChains.includes(id)) {
      throw new Error(
        `Chain ID ${id} is not in the allowlist. Allowed: ${allowedChains.join(", ")}`
      );
    }
    return id;
  }

  static validateRpcUrl(url) {
    if (!url || typeof url !== "string") {
      throw new Error("RPC URL must be a non-empty string");
    }
    try {
      const parsed = new URL(url);
      if (!["https:", "wss:"].includes(parsed.protocol)) {
        throw new Error("RPC URL must use HTTPS or WSS protocol");
      }
      return url;
    } catch (e) {
      if (e.message.includes("RPC URL")) throw e;
      throw new Error("Invalid RPC URL format");
    }
  }
}

// ============================================================
// RATE LIMITER
// ============================================================

class RateLimiter {
  constructor(maxRequests, windowMs) {
    this.maxRequests = maxRequests;
    this.windowMs = windowMs;
    this.requests = new Map();
  }

  check(key) {
    const now = Date.now();
    const windowStart = now - this.windowMs;

    if (!this.requests.has(key)) {
      this.requests.set(key, []);
    }

    const timestamps = this.requests
      .get(key)
      .filter((t) => t > windowStart);
    this.requests.set(key, timestamps);

    if (timestamps.length >= this.maxRequests) {
      throw new Error(
        `Rate limit exceeded for ${key}. Max ${this.maxRequests} requests per ${this.windowMs / 1000}s`
      );
    }

    timestamps.push(now);
    return true;
  }
}

// ============================================================
// TRANSACTION SERVICE
