class TransactionService {
  constructor(config) {
    this._validateConfig(config);

    const rpcUrl = InputValidator.validateRpcUrl(config.rpcUrl);
    this.provider = new ethers.JsonRpcProvider(rpcUrl);
    this.chainId = InputValidator.validateChainId(config.chainId);

    // Initialize secure key manager
    // ENCRYPTION_KEY should come from environment variable or secrets manager
    const encryptionKey =
      config.encryptionKey || process.env.KEYSTORE_ENCRYPTION_KEY;
    if (!encryptionKey) {
      throw new Error(
        "KEYSTORE_ENCRYPTION_KEY environment variable is required"
      );
    }

    this.keyManager = new SecureKeyManager(
      config.keystorePath || "./keystore",
      encryptionKey
    );

    // Rate limiter: max 10 transactions per minute per wallet
    this.rateLimiter = new RateLimiter(10, 60000);

    // Transaction nonce tracking to prevent nonce reuse
    this.nonceTracker = new Map();
    this.nonceLocks = new Map();

    // Gas price limits (in gwei)
    this.maxGasPrice = ethers.parseUnits(
      String(config.maxGasPriceGwei || 500),
      "gwei"
    );
    this.maxGasLimit = BigInt(config.maxGasLimit || 500000);

    // Allowlisted contract addresses
    this.allowlistedContracts = new Set(
      (config.allowlistedContracts || []).map((addr) =>
        ethers.getAddress(addr)
      )
    );

    console.log("[TransactionService] Initialized securely");
    // NEVER log: private keys, encryption keys, or sensitive config
  }

  _validateConfig(config) {
    if (!config || typeof config !== "object") {
      throw new Error("Configuration object is required");
    }
    if (!config.rpcUrl) {
      throw new Error("RPC URL is required in configuration");
    }
    if (!config.chainId) {
      throw new Error("Chain ID is required in configuration");
    }
  }

  /**
   * Import a wallet private key securely.
   * The key is encrypted and stored; never kept in memory.
   */
  importWallet(alias, privateKey) {
    this.keyManager.storeKey(alias, privateKey);
    // Verify the key works by creating a wallet
    const wallet = this.keyManager.getWallet(alias, this.provider);
    const address = wallet.address;
    console.log(
      `[TransactionService] Wallet imported: ${alias} -> ${address}`
    );
    return address;
  }

  /**
   * Get the address for a wallet alias without exposing the private key.
   */
  getAddress(alias) {
    const wallet = this.keyManager.getWallet(alias, this.provider);
    return wallet.address;
  }

  /**
   * Get the balance of a wallet by alias.
   */
  async getBalance(alias) {
    const wallet = this.keyManager.getWallet(alias, this.provider);
    const balance = await this.provider.getBalance(wallet.address);
    return ethers.formatEther(balance);
  }

  /**
   * Send ETH from one wallet to an address.
   * Includes comprehensive validation, rate limiting, and gas checks.
   */
  async sendETH(fromAlias, toAddress, amountInEth) {
    // Validate inputs
    const validatedTo = InputValidator.validateAddress(toAddress);
    const validatedAmount = InputValidator.validateAmount(amountInEth);

    // Rate limiting
    this.rateLimiter.check(`send:${fromAlias}`);

    // Get wallet (key is decrypted only in memory, briefly)
    const wallet = this.keyManager.getWallet(fromAlias, this.provider);

    // Verify chain ID matches expected
    const network = await this.provider.getNetwork();
    if (Number(network.chainId) !== this.chainId) {
      throw new Error(
        `Chain ID mismatch. Expected ${this.chainId}, got ${network.chainId}`
      );
    }

    // Check balance
    const balance = await this.provider.getBalance(wallet.address);
    const amountWei = ethers.parseEther(validatedAmount);

    if (balance < amountWei) {
      throw new Error("Insufficient balance for transaction");
    }

    // Get and validate gas price
    const feeData = await this.provider.getFeeData();
    const gasPrice = feeData.gasPrice || feeData.maxFeePerGas;

    if (gasPrice > this.maxGasPrice) {
      throw new Error(
        `Gas price ${ethers.formatUnits(gasPrice, "gwei")} gwei exceeds maximum ${ethers.formatUnits(this.maxGasPrice, "gwei")} gwei`
      );
    }

    // Get nonce with lock to prevent nonce reuse
    const nonce = await this._getNextNonce(wallet.address);

    // Build transaction
    const tx = {
      to: validatedTo,
      value: amountWei,
      nonce: nonce,
      chainId: this.chainId,
      gasLimit: 21000n, // Standard ETH transfer
    };

    // Use EIP-1559 if available
    if (feeData.maxFeePerGas) {
      tx.maxFeePerGas = feeData.maxFeePerGas;
      tx.maxPriorityFeePerGas = feeData.maxPriorityFeePerGas;
      tx.type = 2;
    } else {
      tx.gasPrice = gasPrice;
    }

    // Verify total cost doesn't exceed balance
    const totalCost = amountWei + 21000n * (gasPrice || feeData.maxFeePerGas);
    if (balance < totalCost) {
      throw new Error("Insufficient balance to cover transaction and gas fees");
    }

    console.log(
      `[TransactionService] Sending ${validatedAmount} ETH from ${wallet.address} to ${validatedTo}`
    );
    // NEVER log: private keys, raw transaction signatures

    // Sign and send
    const txResponse = await wallet.sendTransaction(tx);

    console.log(`[TransactionService] Transaction sent: ${txResponse.hash}`);

    return {
      hash: txResponse.hash,
      from: wallet.address,
      to: validatedTo,
      amount: validatedAmount,
      nonce: nonce,
    };
  }

  /**
   * Interact with a smart contract (write operation).
   * Only allowlisted contracts can be called.
   */
  async callContract(
    fromAlias,
    contractAddress,
    abi,
    functionName,
    args = [],
    valueInEth = "0"
  ) {
    // Validate inputs
    const validatedContractAddr =
      InputValidator.validateAddress(contractAddress);
    const validatedABI = InputValidator.validateContractABI(abi);
    const validatedFunctionName =
      InputValidator.validateFunctionName(functionName);

    // Check contract allowlist
    if (
      this.allowlistedContracts.size > 0 &&
      !this.allowlistedContracts.has(validatedContractAddr)
    ) {
      throw new Error(
        `Contract ${validatedContractAddr} is not in the allowlist`
      );
    }

    // Rate limiting
    this.rateLimiter.check(`contract:${fromAlias}`);

    // Get wallet
    const wallet = this.keyManager.getWallet(fromAlias, this.provider);

    // Verify chain ID
    const network = await this.provider.getNetwork();
    if (Number(network.chainId) !== this.chainId) {
      throw new Error(
        `Chain ID mismatch. Expected ${this.chainId}, got ${network.chainId}`
      );
    }

    // Create contract instance
    const contract = new ethers.Contract(
      validatedContractAddr,
      validatedABI,
      wallet
    );

    // Verify function exists in ABI
    if (!contract[validatedFunctionName]) {
      throw new Error(
        `Function ${validatedFunctionName} not found in contract ABI`
      );
    }

    // Validate value if sending ETH with the call
    const validatedValue =
      valueInEth !== "0"
        ? InputValidator.validateAmount(valueInEth)
        : "0";

    // Estimate gas first
    const estimatedGas = await contract[validatedFunctionName].estimateGas(
      ...args,
      {
        value: ethers.parseEther(validatedValue),
      }
    );

    if (estimatedGas > this.maxGasLimit) {
      throw new Error(
        `Estimated gas ${estimatedGas} exceeds maximum ${this.maxGasLimit}`
      );
    }

    // Check gas price
    const feeData = await this.provider.getFeeData();
    const gasPrice = feeData.gasPrice || feeData.maxFeePerGas;
    if (gasPrice > this.maxGasPrice) {
      throw new Error(
        `Gas price exceeds maximum allowed: ${ethers.formatUnits(this.maxGasPrice, "gwei")} gwei`
      );
    }

    // Get nonce
    const nonce = await this._getNextNonce(wallet.address);

    // Build overrides
    const overrides = {
      value: ethers.parseEther(validatedValue),
      gasLimit: (estimatedGas * 120n) / 100n, // 20% buffer
      nonce: nonce,
    };

    if (feeData.maxFeePerGas) {
      overrides.maxFeePerGas = feeData.maxFeePerGas;
      overrides.maxPriorityFeePerGas = feeData.maxPriorityFeePerGas;
      overrides.type = 2;
    } else {
      overrides.gasPrice = gasPrice;
    }

    console.log(
      `[TransactionService] Calling ${validatedFunctionName} on ${validatedContractAddr} from ${wallet.address}`
    );

    // Execute transaction
    const txResponse = await contract[validatedFunctionName](
      ...args,
      overrides
    );

    console.log(
      `[TransactionService] Contract call sent: ${txResponse.hash}`
    );

    return {
      hash: txResponse.hash,
      from: wallet.address,
      to: validatedContractAddr,
      function: validatedFunctionName,
      nonce: nonce,
    };
  }

  /**
   * Read from a smart contract (no transaction, no gas).
   */
  async readContract(contractAddress, abi, functionName, args = []) {
    const validatedContractAddr =
      InputValidator.validateAddress(contractAddress);
    const validatedABI = InputValidator.validateContractABI(abi);
    const validatedFunctionName =
      InputValidator.validateFunctionName(functionName);

    // Check contract allowlist
    if (
      this.allowlistedContracts.size > 0 &&
      !this.allowlistedContracts.has(validatedContractAddr)
    ) {
      throw new Error(
        `Contract ${validatedContractAddr} is not in the allowlist`
      );
    }

    const contract = new ethers.Contract(
      validatedContractAddr,
      validatedABI,
      this.provider
    );

    if (!contract[validatedFunctionName]) {
      throw new Error(
        `Function ${validatedFunctionName} not found in contract ABI`
      );
    }

    const result = await contract[validatedFunctionName](...args);
    return result;
  }

  /**
   * Wait for a transaction to be confirmed.
   */
  async waitForTransaction(txHash, confirmations = 1) {
    if (!txHash || typeof txHash !== "string" || !/^0x[a-fA-F0-9]{64}$/.test(txHash)) {
      throw new Error("Invalid transaction hash");
    }
    if (confirmations < 1 || confirmations > 50) {
      throw new Error("Confirmations must be between 1 and 50");
    }

    const receipt = await this.provider.waitForTransaction(
      txHash,
      confirmations,
      120000 // 2 minute timeout
    );

    if (!receipt) {
      throw new Error("Transaction confirmation timed out");
    }

    return {
      hash: receipt.hash,
      blockNumber: receipt.blockNumber,
      status: receipt.status === 1 ? "success" : "failed",
      gasUsed: receipt.gasUsed.toString(),
    };
  }

  /**
   * Get next nonce with simple locking to prevent reuse.
   */
  async _getNextNonce(address) {
    const checksumAddr = ethers.getAddress(address);

    // Simple mutex-like behavior
    while (this.nonceLocks.get(checksumAddr)) {
      await new Promise((resolve) => setTimeout(resolve, 100));
    }

    this.nonceLocks.set(checksumAddr, true);

    try {
      const onChainNonce = await this.provider.getTransactionCount(
        checksumAddr,
        "pending"
      );
      const trackedNonce = this.nonceTracker.get(checksumAddr) || 0;
      const nonce = Math.max(onChainNonce, trackedNonce);

      this.nonceTracker.set(checksumAddr, nonce + 1);
      return nonce;
    } finally {
      this.nonceLocks.set(checksumAddr, false);
    }
  }

  /**
   * Clean up resources.
   */
  async destroy() {
    this.nonceTracker.clear();
    this.nonceLocks.clear();
    if (this.provider.destroy) {
      await this.provider.destroy();
    }
    console.log("[TransactionService] Destroyed");
  }
}

